defmodule MyApp.UserController do
  use MyApp.Web, :controller

  alias MyApp.{Repo, User}

  def update(conn, %{"id" => user_id}) do
    user = Repo.get_by!(User, id: user_id)

    changeset = User.changeset(user, params = conn.params["user"])
    changeset = unsafe_validate_required(changeset, [:email, :name])

    case Repo.update(user, changeset) do
      {:ok, updated_user} ->
        conn
          |> put_status(:ok)
          |> render("user_show.html", user: updated_user)

      {:error, error} ->
        conn
          |> put_status(:bad_request)
          |> render("error.html", %{message: "Validation failed. #{inspect(error)}"})
    end
  end
end